const https = require('https');
const http = require('http');

function fetchUrlMetadata(url) {
  return new Promise((resolve, reject) => {
    const parsedUrl = new URL(url);
    const protocol = parsedUrl.protocol === 'https:' ? https : http;
    
    const options = {
      hostname: parsedUrl.hostname,
      port: parsedUrl.port,
      path: parsedUrl.pathname + parsedUrl.search,
      method: 'GET',
      headers: {
        'User-Agent': 'Mozilla/5.0 (compatible; URLMetadataFetcher/1.0)',
        'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
        'Accept-Language': 'en-US,en;q=0.5',
      },
      timeout: 10000
    };

    const req = protocol.request(options, (res) => {
      if (res.statusCode >= 300 && res.statusCode < 400 && res.headers.location) {
        const redirectUrl = new URL(res.headers.location, url).href;
        return fetchUrlMetadata(redirectUrl).then(resolve).catch(reject);
      }

      if (res.statusCode !== 200) {
        return reject(new Error(`HTTP ${res.statusCode}: ${res.statusMessage}`));
      }

      let data = '';
      
      res.on('data', (chunk) => {
        data += chunk;
        if (data.length > 5000000) {
          req.destroy();
          reject(new Error('Response too large'));
        }
      });

      res.on('end', () => {
        try {
          const metadata = parseHtml(data);
          resolve(metadata);
        } catch (error) {
          reject(error);
        }
      });
    });

    req.on('error', (error) => {
      reject(error);
    });

    req.on('timeout', () => {
      req.destroy();
      reject(new Error('Request timeout'));
    });

    req.end();
  });
}

function parseHtml(html) {
  const metadata = {
    title: null,
    description: null,
    ogTitle: null,
    ogDescription: null,
    ogImage: null,
    ogUrl: null,
    ogType: null,
    ogSiteName: null
  };

  const titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
  if (titleMatch) {
    metadata.title = decodeHtmlEntities(titleMatch[1].trim());
  }

  const metaTags = html.match(/<meta[^>]+>/gi) || [];
  
  for (const tag of metaTags) {
    const nameMatch = tag.match(/name=["']([^"']+)["']/i);
    const propertyMatch = tag.match(/property=["']([^"']+)["']/i);
    const contentMatch = tag.match(/content=["']([^"']*)["']/i);
    
    if (!contentMatch) continue;
    
    const content = decodeHtmlEntities(contentMatch[1].trim());
    const attr = nameMatch ? nameMatch[1].toLowerCase() : (propertyMatch ? propertyMatch[1].toLowerCase() : null);
    
    if (!attr) continue;

    switch (attr) {
      case 'description':
        if (!metadata.description) metadata.description = content;
        break;
      case 'og:title':
        metadata.ogTitle = content;
        break;
      case 'og:description':
        metadata.ogDescription = content;
        break;
      case 'og:image':
        metadata.ogImage = content;
        break;
      case 'og:url':
        metadata.ogUrl = content;
        break;
      case 'og:type':
        metadata.ogType = content;
        break;
      case 'og:site_name':
        metadata.ogSiteName = content;
        break;
    }
  }

  return metadata;
}

function decodeHtmlEntities(text) {
  const entities = {
    '&amp;': '&',
    '&lt;': '<',
    '&gt;': '>',
    '&quot;': '"',
    '&#39;': "'",
    '&apos;': "'",
    '&nbsp;': ' '
  };
  
  return text.replace(/&[a-z0-9#]+;/gi, (match) => {
    return entities[match.toLowerCase()] || match;
  });
}

exports.fetchUrlMetadata = async (req, res) => {
  res.set('Access-Control-Allow-Origin', '*');
  
  if (req.method === 'OPTIONS') {
    res.set('Access-Control-Allow-Methods', 'GET, POST');
    res.set('Access-Control-Allow-Headers', 'Content-Type');
    res.set('Access-Control-Max-Age', '3600');
    return res.status(204).send('');
  }

  try {
    const url = req.query.url || req.body?.url;
    
    if (!url) {
      return res.status(400).json({ error: 'URL parameter is required' });
    }

    if (!url.startsWith('http://') && !url.startsWith('https://')) {
      return res.status(400).json({ error: 'Invalid URL format. Must start with http:// or https://' });
    }

    const metadata = await fetchUrlMetadata(url);
    
    res.status(200).json({
      success: true,
      url: url,
      metadata: metadata
    });
  } catch (error) {
    console.error('Error fetching metadata:', error);
    res.status(500).json({
      success: false,
      error: error.message
    });
  }
};